        renumber = [
            ('_section_title("03", "US Market Update")', '_section_title("04", "US Market Update")'),
            ('_section_title("04", "Cross-Asset Regime")', '_section_title("05", "Cross-Asset Regime")'),
            ('_section_title("05", "Macro State Snapshot")', '_section_title("06", "Macro State Snapshot")'),
            ('_section_title("06", "Economic Calendar")', '_section_title("07", "Economic Calendar")'),
            ('_section_title("07", "Biggest Headline of the Day")', '_section_title("08", "Biggest Headline of the Day")'),
            ('_section_title("08", "Global Developments")', '_section_title("09", "Global Developments")'),
            ('_section_title("09", "Earnings Calendar")', '_section_title("10", "Earnings Calendar")'),
            ('_section_title("10", "SEC Filings Monitor")', '_section_title("11", "SEC Filings Monitor")'),
            ('_section_title("11", "Sources")', '_section_title("12", "Sources")'),
        ]

